const axios = require('axios');
const cheerio = require('cheerio');

async function getMetadata(url) {
  try {
    const response = await axios.get(url);
    if (response.status !== 200) {
      throw new Error(`Failed to fetch URL. Status code: ${response.status}`);
    }
    const $ = cheerio.load(response.data);

    let ogTitle = '';
    let ogDescription = '';

    $('meta[name="og:title"]').each((index, element) => {
      const attribute = $(element).attr('content');
      if (attribute && typeof attribute === 'string') {
        ogTitle = attribute;
      }
    });

    $('meta[name="og:description"]').each((index, element) => {
      const attribute = $(element).attr('content');
      if (attribute && typeof attribute === 'string') {
        ogDescription = attribute;
      }
    });

    let title = '';
    $('title').each((index, element) => {
      const attribute = $(element).text().trim();
      if (attribute && typeof attribute === 'string') {
        title = attribute;
      }
    });

    $('meta[name="description"]').each((index, element) => {
      const attribute = $(element).attr('content');
      if (attribute && typeof attribute === 'string') {
        title = attribute;
      }
    });

    return {
      ogTitle,
      ogDescription,
      title
    };
  } catch (error) {
    console.error(`Failed to fetch metadata: ${error.message}`);
    throw error;
  }
}

module.exports = getMetadata;